<template><div class="page"><div class="head"><div><h2>直播课堂</h2><p>加入已选课程直播</p></div><el-button @click="load">刷新</el-button></div>
<el-empty v-if="!loading&&!rooms.length" description="暂无直播安排"/>
<div class="grid" v-loading="loading"><el-card v-for="r in rooms" :key="r.room_id"><div class="status" :class="r.status">{{labels[r.status]}}</div><h3>{{r.title}}</h3><p>{{r.course_name}} · {{r.teacher_name}}</p><p>{{fmt(r.scheduled_start)}}</p><el-button v-if="r.status==='live'" type="danger" @click="$router.push('/student/live/'+r.room_id)">进入直播</el-button></el-card></div></div></template>
<script setup>import{ref,onMounted}from'vue';import{studentRooms}from'../../api/live';const rooms=ref([]),loading=ref(false),labels={scheduled:'未开始',live:'直播中',ended:'已结束',cancelled:'已取消'};const fmt=v=>v?new Date(v).toLocaleString():'--';async function load(){loading.value=true;try{rooms.value=await studentRooms()}finally{loading.value=false}}onMounted(load)</script>
<style scoped>.page{background:#fff;padding:24px;border-radius:16px}.head{display:flex;justify-content:space-between}.head p,p{color:#64748b}.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:16px;margin-top:20px}.status{float:right;padding:4px 10px;border-radius:12px;background:#eef2ff}.status.live{background:#fee2e2;color:#dc2626}</style>
